fetch security.events
| filter event.type == "VULNERABILITY_FINDING"
     AND object.type == "CONTAINER_IMAGE"
     AND isNotNull(component.name)
| filter in(event.provider,$Provider)
| dedup dt.security.risk.level
| fieldsAdd orderHelper = if(dt.security.risk.level == "CRITICAL", 1, else: 
if(dt.security.risk.level == "HIGH", 2, else: 
  if(dt.security.risk.level == "MEDIUM", 3, else: 
    if(dt.security.risk.level == "LOW", 4, else: 
      if(dt.security.risk.level == "NONE", 5, else: 
        if(dt.security.risk.level == "NOT_AVAILABLE", 6)
)))))
| sort orderHelper asc
| summarize rawValues = arrayRemoveNulls(collectDistinct(dt.security.risk.level))
| fields values = if(arraySize(rawValues) > 0, rawValues, else:"None")

fetch security.events
| filter dt.system.bucket == "default_securityevents"
AND event.type=="VULNERABILITY_FINDING"
| filter isNotNull(container_image.digest)
| filter in(event.provider,$Provider)
| dedup {container_image.digest, event.provider, finding.id, object.id, dt.security.risk.level}, sort: {timestamp desc}
// contextualization
| join [
  fetch dt.entity.container_group_instance, from:now()-1h
  | fieldsAdd containerNames, container_group.id=instance_of[dt.entity.container_group], workload.id=belongs_to[dt.entity.cloud_application], workloadName, containerStatus, processes=contains[dt.entity.process_group_instance]
  | fieldsAdd dt.source_entity=coalesce(workload.id,container_group.id)
], kind:leftOuter, on:{right[containerImageDigest]==left[container_image.digest]}, 
  fields:{
    containerNames, dt.source_entity, workloadName, containerStatus, processes
  }
| append [
    fetch security.events
    | filter dt.system.bucket == "default_securityevents"
    AND event.type=="VULNERABILITY_FINDING"
    | filter isNotNull(container_image.digest)
    // now enrich the runtime context
    | join [
        fetch dt.entity.container_group_instance, from:now()-1h
        | fieldsAdd containerNames, containerImageId, container_group.id=instance_of[dt.entity.container_group], workload.id=belongs_to[dt.entity.cloud_application], workloadName, containerStatus, processes=contains[dt.entity.process_group_instance]
        | fieldsAdd dt.source_entity=coalesce(workload.id,container_group.id)
    ], kind:leftOuter, on:{left[container_image.id]==right[containerImageId]},
       fields:{
         containerNames, dt.source_entity, workloadName, containerStatus, processes
       }
]
| filterOut isNull(dt.source_entity)
| dedup {dt.source_entity, containerNames, workloadName, container_image.digest, event.provider, finding.id, object.id, dt.security.risk.level}, sort:{timestamp desc}
| expand dt.entity.process=processes
| fieldsRemove processes
| join [
    fetch dt.entity.process_group_instance, from:now()-1h
], on:{left[dt.entity.process]==right[id]}, kind:leftOuter, fields:{releasesProduct, releasesStage}
| fieldsAdd releasesStage = if(isNull(releasesStage), "None", else:releasesStage)
| fields releasesStage
| dedup releasesStage
| sort releasesStage
| append [data record(releasesStage="All")]
| limit 999999

43.query:
fetch security.events
| filter event.type == "VULNERABILITY_FINDING"
     AND object.type == "CONTAINER_IMAGE"
     AND isNotNull(component.name)
| dedup {object.id, vulnerability.id, component.name, component.version,
         container_image.registry, container_image.repository}, sort: {timestamp desc}
// dashboard filters
| filter in(event.provider, $Provider)
     AND (in("All",$Registry) OR in(container_image.registry, $Registry))
     AND (in("All",$Repository) OR in(container_image.repository, $Repository))
     AND (in("All",$Tag) OR in(container_image.tags, $Tag))
     AND (in("All",$RiskLevel) OR in(dt.security.risk.level, $RiskLevel))
     AND (in("All",$Vulnerability) OR in(vulnerability.id, $Vulnerability))
     AND (in("All",$Component) OR in(component.name, $Component))
// now enrich the runtime context
| join [
    fetch dt.entity.container_group_instance, from:now()-1h
    | fieldsAdd entity.name, containerImageDigest, containerImageName, workloadName, containerStatus, processes=contains[dt.entity.process_group_instance]
], on:{left[container_image.digest]==right[containerImageDigest]}, kind:leftOuter,
   fields:{container_instance.id=id, container_instance.name=entity.name, container_image.name=containerImageName, containerStatus, processes}
| filter isNotNull(container_instance.id) AND contains(containerStatus, "running")
| append [
    fetch security.events
    | filter event.type == "VULNERABILITY_FINDING"
         AND object.type == "CONTAINER_IMAGE"
         AND isNotNull(component.name)
      // dashboard filters
    | filter in(event.provider, $Provider)
     AND (in("All",$Registry) OR in(container_image.registry, $Registry))
     AND (in("All",$Repository) OR in(container_image.repository, $Repository))
     AND (in("All",$Tag) OR in(container_image.tags, $Tag))
     AND (in("All",$RiskLevel) OR in(dt.security.risk.level, $RiskLevel))
     AND (in("All",$Vulnerability) OR in(vulnerability.id, $Vulnerability))
     AND (in("All",$Component) OR in(component.name, $Component))
    // now enrich the runtime context
    | join [
        fetch dt.entity.container_group_instance, from:now()-1h
        | fieldsAdd entity.name, containerImageId, containerImageName, workloadName, containerStatus, processes=contains[dt.entity.process_group_instance]
    ], on:{left[container_image.id]==right[containerImageId]}, kind:leftOuter,
       fields:{container_instance.id=id, container_instance.name=entity.name, container_image.name=containerImageName, containerStatus, processes}
    | filter isNotNull(container_instance.id) AND contains(containerStatus, "running")
]
| dedup {container_instance.id}
| expand dt.entity.process=processes
| fieldsRemove processes
| join [
    fetch dt.entity.process_group_instance, from:now()-1h
], on:{left[dt.entity.process]==right[id]}, kind:leftOuter, fields:{releasesProduct, releasesStage}
| fieldsAdd releasesStage = if(isNull(releasesStage), "None", else:releasesStage)
| filter releasesStage!="None" AND in(releasesStage,$ProductStage)
// aggregation and custom filtering
| dedup {object.id, vulnerability.id, component.name,
         container_image.registry, container_image.repository, container_image.tags}, sort: {timestamp desc}
| summarize {
    `Risk score`=toDouble(takeMax(dt.security.risk.score)),
    `Last finding`=takeMax(timestamp),
    `Container images`=countDistinctExact(container_image.digest)
    }, 
    by:{Vulnerability=vulnerability.id, `Risk level`=dt.security.risk.level}
| sort {`Risk score`, direction:"descending"}, {`Container images`, direction:"descending"}
| fields `Risk level`, Vulnerability, `Container images`
| limit 10

