63.query:
fetch dt.entity.container_group_instance
| fieldsAdd entity.name, container_instance.status=containerStatus, containerImageDigest, containerImageName, workloadName, workload.id=belongs_to[dt.entity.cloud_application], containerStatus, processes=contains[dt.entity.process_group_instance]
// filter for those that have running instances in production
| filter contains(container_instance.status, "running")
| join [
  fetch security.events
  | filter event.type == "VULNERABILITY_FINDING"
     AND object.type == "CONTAINER_IMAGE"
     AND isNotNull(component.name)
  | dedup {object.id, vulnerability.id, component.name, component.version,
         container_image.registry, container_image.repository}, sort: {timestamp desc}
  // dashboard filters
  | filter in(event.provider, $Provider)
     AND (in("All",$Registry) OR in(container_image.registry, $Registry))
     AND (in("All",$Repository) OR in(container_image.repository, $Repository))
     AND (in("All",$Tag) OR in(container_image.tags, $Tag))
     AND (in("All",$RiskLevel) OR in(dt.security.risk.level, $RiskLevel))
     AND (in("All",$Vulnerability) OR in(vulnerability.id, $Vulnerability))
     AND (in("All",$Component) OR in(component.name, $Component))
  | filterOut isNull(container_image.digest)
  | summarize {
      Findings=countIf(in(event.type,{"VULNERABILITY_FINDING"})),
      Scans=countIf(in(event.type,{"VULNERABILITY_SCAN"}))
    }, by:{container_image.digest, event.provider}
], kind:leftOuter, on:{left[containerImageDigest]==right[container_image.digest]}
| fieldsAdd covered=if(isNotNull(right.container_image.digest), "Covered", else:"Not covered")
| filterOut covered=="Not covered"
| expand dt.entity.process=processes
| fieldsRemove processes
| join [
    fetch dt.entity.process_group_instance, from:now()-3h
], on:{left[dt.entity.process]==right[id]}, kind:leftOuter, fields:{releasesProduct, releasesStage}
| fieldsAdd releasesStage=if(isNull(releasesStage), "Other", else:releasesStage)
//| filter releasesStage!="None" AND in(releasesStage,$ProductStage)
| summarize {
  Containers=countDistinctExact(workload.id)
}, by:{releasesStage}

